#include <bits/stdc++.h>
using namespace std;

int m,len1,len2;
long long f[65],p[2][65];

int main(){
    f[0]=f[1]=1;
    for(int i=2;i<=60;i++)
        f[i]=f[i-2]+f[i-1];
    scanf("%d",&m);
    while(m--){
        long long a,b;
        scanf("%lld%lld",&a,&b);
        len1=1,len2=1;
        p[0][1]=a,p[1][1]=b;
        while(a>1){
            int l=1,r=60;
            while(l<r){
                int mid=l+r+1>>1;
                if(f[mid]<a)
                    l=mid;
                else
                    r=mid-1;
            }
            a-=f[l];
            p[0][++len1]=a;
        }
        while(b>1){
            int l=1,r=60;
            while(l<r){
                int mid=l+r+1>>1;
                if(f[mid]<b)
                    l=mid;
                else
                    r=mid-1;
            }
            b-=f[l];
            p[1][++len2]=b;
        }
        int ans=0;
        while(p[0][len1-ans]==p[1][len2-ans] && ans<min(len1,len2))
            ans++;
        printf("%lld\n",p[0][len1-ans+1]);
    }
    return 0;
}
